#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int zeros = 0, neg = 0;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (x == 0) zeros = 1; // we only need to know existence
            else if (x < 0) ++neg;
        }
        if (zeros) printf("0\n");
        else if (neg % 2 == 0) printf("0\n");
        else printf("1\n");
    }
    return 0;
}

