import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            StringTokenizer st = new StringTokenizer(br.readLine());
            int zeros = 0, neg = 0;
            for (int i = 0; i < N; i++) {
                int x = Integer.parseInt(st.nextToken());
                if (x == 0) zeros = 1;
                else if (x < 0) neg++;
            }
            if (zeros == 1) out.append(0).append('\n');
            else if (neg % 2 == 0) out.append(0).append('\n');
            else out.append(1).append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        zeros = 0
        neg = 0
        for _ in range(N):
            x = int(next(it))
            if x == 0:
                zeros = 1
            elif x < 0:
                neg += 1
        if zeros:
            out_lines.append('0')
        elif neg % 2 == 0:
            out_lines.append('0')
        else:
            out_lines.append('1')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

